// frontend/src/components/Layout.js
import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// Images confirmed in src/components/ from VS Code file tree screenshot
import pic3 from './lightmode.jpg';
import pic4 from './darkmode.png';
import pic5 from './gmail.png';
import pic6 from './facebook.png';

// Logo from src/pictures/
import LogoK from '../pictures/LogoK.jpg';

const Layout = ({ children }) => {
  const [isDarkMode, setIsDarkMode] = useState(
    () => localStorage.getItem('darkmode') === 'active'
  );
  const { user, logout } = useAuth();
  const location  = useLocation();
  const navigate  = useNavigate();

  useEffect(() => {
    if (isDarkMode) {
      document.body.classList.add('darkmode');
      localStorage.setItem('darkmode', 'active');
    } else {
      document.body.classList.remove('darkmode');
      localStorage.setItem('darkmode', 'inactive');
    }
  }, [isDarkMode]);

  const toggleDark   = () => setIsDarkMode(prev => !prev);
  const isActive     = (path) => location.pathname === path ? 'active' : '';
  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <>
      {/* ── Header ── */}
      <header>
        <div className="header-container">
          <img src={LogoK} alt="Logo" className="header-logo" />
          <h1>TRAVEL JOURNAL</h1>
        </div>

        {/* Dark / light toggle */}
        <div
          className="mode-toggle"
          onClick={toggleDark}
          title={isDarkMode ? 'Switch to light mode' : 'Switch to dark mode'}
        >
          <img
            src={isDarkMode ? pic4 : pic3}
            alt={isDarkMode ? 'Light mode' : 'Dark mode'}
          />
        </div>
      </header>

      {/* ── Navigation ── */}
      <nav className="horizontal-nav">
        <ul>
          <li><Link to="/home"    className={isActive('/home')}>Home</Link></li>
          <li><Link to="/about"   className={isActive('/about')}>About Us</Link></li>
          <li><Link to="/contact" className={isActive('/contact')}>Contact Us</Link></li>

          {/* Logged OUT */}
          {!user && (
            <>
              <li><Link to="/register" className={isActive('/register')}>Register</Link></li>
              <li><Link to="/login"    className={isActive('/login')}>Login</Link></li>
            </>
          )}

          {/* Logged IN */}
          {user && (
            <>
              <li><Link to="/create-post" className={isActive('/create-post')}>Write Post</Link></li>
              <li><Link to="/profile"     className={isActive('/profile')}>Profile</Link></li>
              {user.role === 'admin' && (
                <li><Link to="/admin" className={isActive('/admin')}>Admin</Link></li>
              )}
              <li>
                <button className="nav-logout-btn" onClick={handleLogout}>
                  Logout ({user.name})
                </button>
              </li>
            </>
          )}
        </ul>
      </nav>

      {/* ── Page Content ── */}
      <main>{children}</main>

      {/* ── Footer ── */}
      <footer className="footer">
        <div className="footer-logos">
          <div className="footer-item">
            <img src={pic5} alt="Gmail" className="footer-logo" />
            <span>krishanepadilla@gmail.com</span>
          </div>
          <div className="footer-item">
            <img src={pic6} alt="Facebook" className="footer-logo" />
            <span>krishane@facebook.com</span>
          </div>
        </div>
        <p>&copy; All Rights Reserved 2026</p>
      </footer>
    </>
  );
};

export default Layout;
